UPDATE seckill_products
product_name = #{productName}, product_image = #{productImage}, seckill_price = #{seckillPrice}, stock = #{stock}, origin_stock = #{originStock}, start_time = #{startTime}, end_time = #{endTime}, status = #{status}, update_time = NOW()
WHERE id = #{id}

UPDATE seckill_products
SET stock = stock - 1, version = version + 1, update_time = NOW()
WHERE id = #{id} AND stock > 0 AND version = #{version}
